import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Swal from 'sweetalert2';
import Navbar from './components/Navbar';
import Katalog from './pages/Katalog';
import DetailProduk from './pages/DetailProduk';
import Keranjang from './pages/Keranjang';
import Login from './pages/Login';

function App() {
  const [kataKunci, setKataKunci] = useState('');
  const [keranjang, setKeranjang] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false); // Memori status login pelanggan

  const tambahKeKeranjang = (produk, qty = 1) => {
    const adaDiKeranjang = keranjang.find((item) => item.id === produk.id);
    if (adaDiKeranjang) {
      setKeranjang(keranjang.map((item) =>
        item.id === produk.id ? { ...adaDiKeranjang, jumlah: adaDiKeranjang.jumlah + qty } : item
      ));
    } else {
      setKeranjang([...keranjang, { ...produk, jumlah: qty }]);
    }
    Swal.fire({
      icon: 'success', title: 'Berhasil!',
      text: `${qty} ${produk.nama} masuk keranjang.`,
      showConfirmButton: false, timer: 1500, toast: true, position: 'top-end'
    });
  };

  return (
    <Router>
      <Navbar setKataKunci={setKataKunci} jumlahKeranjang={keranjang.length} />
      <Routes>
        <Route path="/" element={<Katalog kataKunci={kataKunci} tambahKeKeranjang={tambahKeKeranjang} />} />
        <Route path="/produk/:id" element={<DetailProduk tambahKeKeranjang={tambahKeKeranjang} />} />
        <Route 
          path="/keranjang" 
          element={<Keranjang keranjang={keranjang} setKeranjang={setKeranjang} isLoggedIn={isLoggedIn} />} 
        />
        <Route 
          path="/login" 
          element={<Login setIsLoggedIn={setIsLoggedIn} />} 
        />
      </Routes>
    </Router>
  );
}

export default App;
